/**
 * 音频插件基类。
 *
 * 主线程上的 AudioExtension 只承载控制面状态和生命周期。实时音频处理放在
 * extensionDefinition 指向的 AudioWorklet 侧插件中；框架每次把 128 采样
 * 直接传给 worklet 侧插件的 processAudioFrame()。
 *
 * @public
 */
export declare abstract class AudioExtension extends Extension implements IAudioExtension {
    get kind(): Kind;
    /**
     * 框架级兼容性检测：音频实时处理依赖 AudioWorklet。
     *
     * 静态方法，集成方可在不实例化插件的前提下直接调用（`MyAudioExtension.checkCompatibility()`）。
     * 检测 `AudioWorkletNode` 与 `AudioContext`（含 `webkitAudioContext`）的 `audioWorklet`
     * 能力是否存在。具体插件可覆写并调用 `super.checkCompatibility()` 叠加自身依赖（如 WebAssembly、SIMD）。
     */
    static checkCompatibility(): boolean;
    /**
     * 创建一个绑定到给定音频 track 的 `AudioExtensionManager`。
     *
     * Escape hatch：供宿主 SDK 在**不对框架做 value import** 的前提下，经"业务传入的插件
     * 构造器"触达框架运行时。内部委派到 globalThis 单例（见 `singleton.ts` 的
     * `ensureRuntime`），因此即便页面上存在多份框架副本，全页面也只有一份活跃 runtime。
     *
     * 注意：manager 是 **track 级**、托管该 track 上所有插件的对象，与调用该静态方法的具体
     * 插件构造器实例无关——这里只是把构造器当作框架运行时的入口句柄。
     */
    static createAudioExtensionManager(track: AudioTrackLike): AudioExtensionManager;
    protected _audioContext: AudioContext | null;
    protected _sampleRate: number;
    init(context: AudioExtensionContext): void;
    destroy(options?: ExtensionDestroyOptions): void;
    applyEffect(): any;
}

/**
 * 音频插件构造器类型。
 * @public
 */
export declare interface AudioExtensionConstructor<T extends IAudioExtension = IAudioExtension> {
    new (...args: any[]): T;
    readonly extensionDefinition?: AudioExtensionDefinition;
    /**
     * 静态兼容性检测：可在不实例化插件的前提下直接调用，例如
     * `if (!MyAudioExtension.checkCompatibility()) { ... } else { manager.useExtension(MyAudioExtension); }`。
     * 由 `AudioExtension` 基类提供默认实现（AudioWorklet 检测），子类可覆写叠加自身依赖。
     */
    checkCompatibility?(): boolean;
    /**
     * 创建一个绑定到给定音频 track 的 `AudioExtensionManager`。
     *
     * 由 `AudioExtension` 基类提供的静态方法（子类继承），委派到框架的 globalThis 单例运行时。
     * 宿主 SDK 可借此在**仅做类型依赖**的前提下创建 manager，无需 value import 框架。
     * 详见 `extension_audio.ts` 中的实现与 `singleton.ts`。
     */
    createAudioExtensionManager(track: AudioTrackLike): AudioExtensionManager;
}

