/**
 * 视频插件接口。
 *
 * 框架调度策略：
 * 1. 收集所有 enabled 插件，按 useExtension 顺序排列
 * 2. 按顺序 ping-pong 执行每个插件的 applyEffect
 * 3. 最终结果 blit 到 canvas 输出
 *
 * 常见插件路径：
 * - 纯 GPU 路径：input texture → output texture。零额外 CPU 拷贝，效率最高。
 *   例：SuperClarity、Beauty。所有新插件优先采用这一模式。
 * - VideoFrame 兼容路径：框架 blit texture → canvas → VideoFrame → 插件
 *   → 插件返回 VideoFrame → 框架 texImage2D 回 texture。会增加 CPU↔GPU 往返。
 *   仅建议用于无法适配 TEXTURE 模式的存量插件迁移。
 * - Worker 后端：框架把帧 I/O 放到 Worker，中间仍复用同一套 Extension 接口。
 *
 * ─── 与业务侧的双向通信 ───
 *
 * - 入站（业务 → 插件）：唯一入口是 {@link IVideoExtension.setOptions | setOptions}。
 *   配置、甚至水印图片等都通过它声明式地下发，框架自动把图片 / ArrayBuffer 等
 *   不可克隆数据转成 Transferable 后跨 Worker 边界传递。
 * - 出站（插件 → 业务）：插件调用继承自 {@link EventEmitter} 的 `emit(name, data)`，
 *   框架把它转发到主线程代理，业务侧通过代理的 `on(name, handler)` 监听
 *   （例如逐帧 face landmark 数据）。
 *
 * @typeParam TOptions - 该插件 `setOptions` 接受的配置形状。
 *
 * @public
 */
export declare interface IVideoExtension<TOptions = Record<string, unknown>> extends IExtension {
    readonly enabled: boolean;
    readonly mode: VideoExtensionMode;
    /**
     * 插件是否支持 CPU 回退模式。
     *
     * 当 WebGL context 丢失时，框架会对 supportsCPUMode=true 的插件
     * 调用 `applyEffect({ kind: "cpu" })` 进行 CPU 回退处理。
     * 不支持 CPU 模式的插件在 context 丢失期间会被跳过。
     * 默认 false。
     */
    readonly supportsCPUMode: boolean;
    init(context: VideoExtensionContext): void | Promise<void>;
    destroy(options?: ExtensionDestroyOptions): void;
    /**
     * 唯一的入站配置入口（声明式）。
     *
     * 业务侧的所有配置更新都经由此方法下发：插件根据传入的配置自行 diff 并应用。
     * 配置中的图片（HTMLImageElement / ImageBitmap）、ArrayBuffer 等不可结构化克隆
     * 的数据，会由框架在跨 Worker 边界前自动转换为 Transferable，插件无需手动序列化。
     *
     * 框架在插件 `init()` 完成后会用 `useExtension()` 的初始 `extensionOptions`
     * 自动调用一次本方法，因此「初始配置」与「运行时更新」走同一段代码路径。
     *
     * 返回的 Promise 在配置应用完成（worker 模式下为 Worker 内应用完成）后 resolve，
     * 出错时 reject，业务侧可 await 并 try/catch。
     *
     * ─── 重放（context loss / worker 重启）：框架自动深合并，作者无需配合 ───
     *
     * 框架会缓存每次下发的 options，用于 WebGL context 丢失 / Worker 重启后重建实例时
     * **自动重放**配置。缓存合并由框架统一处理（见 `internal/options_merge.ts`）：
     *
     * - **普通对象（plain object）子树会被深合并**：先 `setOptions({ beauty: { smoothness } })`
     *   再 `setOptions({ beauty: { whitening } })`，重放时 `smoothness` 与 `whitening` 都在。
     *   分片下发的配置天然保真，插件作者**无需**在实例内部自行累积，也无需把完整状态
     *   每次整体传入。
     * - **数组整体替换**：`setOptions({ watermarks: [...] })` 传入新列表即替换旧列表，
     *   不会把多次传入的数组元素并起来。这保留了"传入完整列表即替换全部"的声明式语义。
     * - **类实例 / ImageBitmap / ArrayBuffer 等非普通对象整体替换**（不深克隆）。
     *
     * 即：嵌套对象会累积、数组会替换。绝大多数配置形状都能直接得到符合直觉的重放结果，
     * 无需任何额外约定。
     */
    setOptions(options: Partial<TOptions>): void | Promise<void>;
    /** 统一处理入口：GPU 模式传入纹理帧，CPU 模式传入 VideoFrame。 */
    applyEffect(frame: Frame): Promise<void | VideoFrame>;
    /**
     * VIDEO_FRAME 模式的处理方法。
     * 在 GPU 管线中，框架自动做 texture ↔ VideoFrame 转换后调用此方法。
     * 在 CPU 管线中，直接收到 VideoFrame。
     *
     * 也可以通过 applyEffect(frame) 处理 kind === "cpu" 来替代。
     */
    processVideoFrame?(frame: VideoFrame): Promise<VideoFrame>;
}

